import torch
import torch.nn as nn
import torch.nn.functional as F
import torch.distributed as dist


def _world_size():
    if dist.is_available() and dist.is_initialized():
        return dist.get_world_size()
    return 1


def _rank():
    if dist.is_available() and dist.is_initialized():
        return dist.get_rank()
    return 0


class _AllGatherLastDim(torch.autograd.Function):
    """Gather local tensors along the last dim (forward all_gather + concat).

    Backward scatters the gradient back so each rank keeps only its slice.
    """

    @staticmethod
    def forward(ctx, input_):
        world = _world_size()
        ctx.world = world
        ctx.rank = _rank()
        if world == 1:
            return input_
        input_ = input_.contiguous()
        tensors = [torch.empty_like(input_) for _ in range(world)]
        dist.all_gather(tensors, input_)
        return torch.cat(tensors, dim=-1)

    @staticmethod
    def backward(ctx, grad_output):
        world = ctx.world
        if world == 1:
            return grad_output
        chunks = grad_output.chunk(world, dim=-1)
        return chunks[ctx.rank].contiguous()


class _AllReduce(torch.autograd.Function):
    """Sum partial outputs across ranks (forward all_reduce, backward identity)."""

    @staticmethod
    def forward(ctx, input_):
        world = _world_size()
        if world == 1:
            return input_
        output = input_.clone()
        dist.all_reduce(output)
        return output

    @staticmethod
    def backward(ctx, grad_output):
        return grad_output


class ColumnParallelLinear(torch.nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        world = _world_size()
        rank = _rank()
        assert out_features % world == 0, \
            "out_features must be divisible by world_size"
        self.in_features = in_features
        self.out_features = out_features
        self.local_out_features = out_features // world

        start = rank * self.local_out_features
        end = start + self.local_out_features
        weight_shard = master_weight[start:end, :].contiguous().clone()
        self.weight = nn.Parameter(weight_shard)

        if bias:
            self.bias = nn.Parameter(
                torch.zeros(
                    self.local_out_features,
                    dtype=self.weight.dtype,
                    device=self.weight.device,
                )
            )
        else:
            self.register_parameter("bias", None)

    def forward(self, input_):
        local_output = F.linear(input_, self.weight, self.bias)
        return _AllGatherLastDim.apply(local_output)


class RowParallelLinear(torch.nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        world = _world_size()
        rank = _rank()
        assert in_features % world == 0, \
            "in_features must be divisible by world_size"
        self.in_features = in_features
        self.out_features = out_features
        self.local_in_features = in_features // world

        start = rank * self.local_in_features
        end = start + self.local_in_features
        weight_shard = master_weight[:, start:end].contiguous().clone()
        self.weight = nn.Parameter(weight_shard)

        if bias:
            self.bias = nn.Parameter(
                torch.zeros(
                    out_features,
                    dtype=self.weight.dtype,
                    device=self.weight.device,
                )
            )
        else:
            self.register_parameter("bias", None)

    def forward(self, input_):
        local_output = F.linear(input_, self.weight)
        output = _AllReduce.apply(local_output)
        if self.bias is not None:
            output = output + self.bias
        return output
